const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.lead_id || !body.message) return { json: { _empty: true, error: 'lead_id and message required' } };
return { json: {
  _authorized: true,
  lead_id: body.lead_id,
  channel: body.channel || 'whatsapp',
  message: String(body.message).slice(0, 2000)
} };

const ctx = $('Build Claude Prompt').item.json;
const assessment = ctx.assessment;
const resp = $input.item.json || {};
let text = '';
try { text = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let parsed = null;
try { parsed = JSON.parse(String(text).replace(/```json|```/g, '').trim()); } catch (e) {}
if (!parsed) parsed = { action: 'clarify', next_question: 'Sorry, could you say that again?', client_situation_update: {}, reasoning: 'parse_failed', risk_tolerance: null };

const valid = ['ask_next','clarify','complete'];
if (valid.indexOf(parsed.action) < 0) parsed.action = 'clarify';

// Merge situation update + append answer to qa_history.
const situation = assessment.client_situation || {};
const history = Array.isArray(situation.qa_history) ? situation.qa_history.slice() : [];
if (history.length > 0) {
  const last = history[history.length - 1];
  if (last && !last.a) { last.a = ctx.message; last.answered_at = new Date().toISOString(); }
}
if (parsed.action !== 'complete' && parsed.next_question) {
  history.push({ q: parsed.next_question, a: null, asked_at: new Date().toISOString() });
}
const updatedSituation = Object.assign({}, situation, parsed.client_situation_update || {}, { qa_history: history, expected_next: parsed.action === 'complete' ? null : { type: 'text' } });

const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

return { json: {
  assessment_id: assessment.id,
  client_id: assessment.client_id,
  lead_id: assessment.lead_id,
  channel: ctx.channel,
  patch: {
    client_situation: updatedSituation,
    risk_tolerance: parsed.risk_tolerance || assessment.risk_tolerance,
    status: parsed.action === 'complete' ? 'client_review' : 'in_progress',
    updated_at: new Date().toISOString()
  },
  send_question: parsed.action !== 'complete' ? parsed.next_question : null,
  trigger_needs_analysis: parsed.action === 'complete',
  tokens: tokens
} };
